jsonCopier le code{
  "project_name": {
    "description": "Short, distinctive name for the project.",
    "example": "Daily Spark"
  },
  "context": {
    "description": "One or two sentences explaining the background and intent.",
    "example": "A tiny daily prompt site to spark a small positive action."
  },
  "objectives": {
    "description": "Clear, measurable goals; what success looks like in plain terms.",
    "example": ["Show one daily challenge", "Keep UX under 1s to load"]
  },
  "audience": {
    "description": "Who this is for and any key traits that influence decisions.",
    "example": "Busy people who want a tiny dose of motivation"
  },
  "agent_persona": {
    "description": "Tone and personality of the agent executing the brief.",
    "example": "Calm, curious, lightly playful; favors clarity over flash"
  },
  "agent_mission": {
    "description": "What the agent is responsible for delivering end-to-end.",
    "example": "Translate the brief into a minimal, working experience that fits constraints"
  },
  "constraints": {
    "description": "Hard rules and guardrails (visual, technical, operational).",
    "example": ["White background", "Max 3 colors", "No images", "Sans-serif type"]
  },
  "style_and_tone": {
    "description": "Desired feel of copy and micro-interactions.",
    "example": "Light, kind, simple; gentle micro-transitions only"
  },
  "scope": {
    "description": "What is in/out; pages, features, and limits.",
    "example": "In: Home, Daily challenge, Archives. Out: Accounts, external APIs"
  },
  "deliverables": {
    "description": "Concrete outputs expected at the end.",
    "example": ["Structured idea list", "Minimal UI", "Local storage of completed items"]
  },
  "inputs": {
    "description": "Materials provided to the agent at start (files, lists, copy).",
    "example": ["Seed list of 50 challenges", "Color tokens (primary/secondary/accent)"]
  },
  "outputs": {
    "description": "Artifacts produced with format expectations.",
    "example": ["Clean file tree", "README with run instructions"]
  },
  "acceptance_criteria": {
    "description": "Binary checks to confirm the work meets the brief.",
    "example": ["Loads offline", "No images used", "Challenge shown in <1s"]
  },
  "workflow_overview": {
    "description": "High-level sequence (sequential or parallel) of ~10 steps.",
    "example": ["Define colors", "Seed ideas", "Build UI shell", "Wire generator", "Add local save", "Archive view", "Copy polish", "Keyboard nav", "Perf pass", "Finalize docs"]
  },
  "tools_and_tech": {
    "description": "Allowed/forbidden tools, libraries, and versions.",
    "example": { "allowed": ["Vanilla HTML/CSS/JS"], "forbidden": ["Image assets", "External APIs"] }
  },
  "data_and_persistence": {
    "description": "Where data lives, privacy constraints, and lifespan.",
    "example": "Browser localStorage only; no network calls"
  },
  "assumptions": {
    "description": "Reasonable premises that, if false, may affect delivery.",
    "example": ["User visits once per day", "Modern evergreen browsers"]
  },
  "risks_and_mitigations": {
    "description": "Known risks with a simple fallback strategy.",
    "example": ["No JS → show static challenge of the day as plain HTML"]
  },
  "success_metrics": {
    "description": "Simple indicators that the product hits the intent.",
    "example": ["Time-to-first-challenge < 1s", "First-use smile test in user feedback"]
  },
  "documentation": {
    "description": "What to document and where.",
    "example": ["README (setup, run, build)", "CONTRIBUTING (style, colors, copy)"]
  },
  "optional_fields": {
    "creative_constraints": {
      "description": "Extra stylistic guardrails (voice, microcopy rules).",
      "example": ["Sentences ≤ 12 words", "No exclamation points"]
    },
    "glossary": {
      "description": "Short definitions for domain terms to avoid ambiguity.",
      "example": { "challenge": "One mini-task shown per day" }
    },
    "evaluation_rubric": {
      "description": "Grading grid the agent can self-check against.",
      "example": ["Clarity (0–5)", "Simplicity (0–5)", "Performance (0–5)"]
    }
  }
}

